import{_ as o,c as t,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Конфиденциальность: защита данных | opencode-supermemory","description":"Узнайте механизмы защиты конфиденциальности opencode-supermemory. Используйте тег private для удаления чувствительных данных, безопасно настройте API Key и поймите поток данных.","frontmatter":{"title":"Конфиденциальность: защита данных | opencode-supermemory","sidebarTitle":"Конфиденциальность","subtitle":"Конфиденциальность: защита данных","description":"Узнайте механизмы защиты конфиденциальности opencode-supermemory. Используйте тег private для удаления чувствительных данных, безопасно настройте API Key и поймите поток данных.","tags":["Конфиденциальность","Безопасность","Настройка"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"ru/supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"ru/supermemoryai/opencode-supermemory/security/privacy/index.md"}'),s={name:"ru/supermemoryai/opencode-supermemory/security/privacy/index.md"};function i(n,e,d,c,l,p){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="конфиденциальность-и-безопасность-данных-как-защитить-вашу-конфиденциальную-информацию" tabindex="-1">Конфиденциальность и безопасность данных: как защитить вашу конфиденциальную информацию <a class="header-anchor" href="#конфиденциальность-и-безопасность-данных-как-защитить-вашу-конфиденциальную-информацию" aria-label="Permalink to &quot;Конфиденциальность и безопасность данных: как защитить вашу конфиденциальную информацию&quot;">​</a></h1><h2 id="что-вы-сможете-сделать-после-изучения" tabindex="-1">Что вы сможете сделать после изучения <a class="header-anchor" href="#что-вы-сможете-сделать-после-изучения" aria-label="Permalink to &quot;Что вы сможете сделать после изучения&quot;">​</a></h2><ul><li><strong>Понять, куда уходят данные</strong>: Четко знать, какие данные будут загружены в облако, а какие останутся локально.</li><li><strong>Освоить техники удаления чувствительных данных</strong>: Научиться использовать тег <code>&lt;private&gt;</code> для предотвращения загрузки чувствительной информации (например, паролей, ключей).</li><li><strong>Безопасное управление ключами</strong>: Научиться настраивать <code>SUPERMEMORY_API_KEY</code> самым безопасным способом.</li></ul><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>При использовании opencode-supermemory критически важно понимать поток данных:</p><ol><li><strong>Облачное хранение</strong>: Ваши памяти (Memories) хранятся в облачной базе данных Supermemory, а не в локальных файлах. Это означает, что вам нужно сетевое подключение для доступа к памятям.</li><li><strong>Локальное удаление чувствительных данных</strong>: Для защиты конфиденциальности плагин до отправки данных в облако выполняет удаление чувствительных данных <strong>локально</strong>.</li><li><strong>Явный контроль</strong>: Плагин не автоматически сканирует и загружает все файлы, только когда Agent явно вызывает инструмент <code>add</code> или триггерирует сжатие, соответствующее содержимое обрабатывается.</li></ol><h3 id="механизм-удаления-чувствительных-данных" tabindex="-1">Механизм удаления чувствительных данных <a class="header-anchor" href="#механизм-удаления-чувствительных-данных" aria-label="Permalink to &quot;Механизм удаления чувствительных данных&quot;">​</a></h3><p>Плагин имеет встроенный простой фильтр, специально распознающий тег <code>&lt;private&gt;</code>.</p><ul><li><strong>Ввод</strong>: <code>Пароль базы данных здесь - &lt;private&gt;123456&lt;/private&gt;</code></li><li><strong>Обработка</strong>: Плагин обнаруживает тег, заменяет содержимое на <code>[REDACTED]</code>.</li><li><strong>Загрузка</strong>: <code>Пароль базы данных здесь - [REDACTED]</code></li></ul><div class="info custom-block"><p class="custom-block-title">Совет</p><p>Этот процесс происходит внутри кода плагина и завершается до того, как данные покидают ваш компьютер.</p></div><h2 id="следуите-моему-примеру" tabindex="-1">Следуйте моему примеру <a class="header-anchor" href="#следуите-моему-примеру" aria-label="Permalink to &quot;Следуйте моему примеру&quot;">​</a></h2><h3 id="шаг-1-безопасная-настроика-api-key" tabindex="-1">Шаг 1: Безопасная настройка API Key <a class="header-anchor" href="#шаг-1-безопасная-настроика-api-key" aria-label="Permalink to &quot;Шаг 1: Безопасная настройка API Key&quot;">​</a></h3><p>Хотя вы можете напрямую записать API Key в файл конфигурации, но для предотвращения случайной утечки (например, случайного обмена файлом конфигурации с другими) мы рекомендуем понять логику приоритета.</p><p><strong>Правило приоритета</strong>:</p><ol><li><strong>Файл конфигурации</strong> (<code>~/.config/opencode/supermemory.jsonc</code>): Наивысший приоритет.</li><li><strong>Переменная среды</strong> (<code>SUPERMEMORY_API_KEY</code>): Если она не установлена в файле конфигурации, используется эта переменная.</li></ol><p><strong>Рекомендуемый подход</strong>: Если вы хотите гибко переключаться или использовать в среде CI/CD, используйте переменные среды. Если вы личный разработчик, настройка в файле JSONC в пользовательском каталоге также безопасна (потому что она не в вашем Git-репозитории проекта).</p><h3 id="шаг-2-использование-тега-private" tabindex="-1">Шаг 2: Использование тега <code>&lt;private&gt;</code> <a class="header-anchor" href="#шаг-2-использование-тега-private" aria-label="Permalink to &quot;Шаг 2: Использование тега `&lt;private&gt;`&quot;">​</a></h3><p>Когда вы позволяете Agent запомнить содержимое, содержащее чувствительную информацию, через естественный язык в диалоге, вы можете использовать тег <code>&lt;private&gt;</code> для обертывания чувствительной части.</p><p><strong>Демонстрация действия</strong>:</p><p>Скажите Agent:</p><blockquote><p>Пожалуйста, запомните, IP базы данных в производственной среде - 192.168.1.10, но пароль root - <code>&lt;private&gt;SuperSecretPwd!&lt;/private&gt;</code>, не раскрывайте пароль.</p></blockquote><p><strong>Что вы должны увидеть</strong>: Agent вызывает инструмент <code>supermemory</code> для сохранения памяти. Хотя ответ Agent может содержать пароль (потому что он в контексте), <strong>фактическая память, сохраненная в облаке Supermemory, уже удалена</strong>.</p><h3 id="шаг-3-проверка-результата-удаления-чувствительных-данных" tabindex="-1">Шаг 3: Проверка результата удаления чувствительных данных <a class="header-anchor" href="#шаг-3-проверка-результата-удаления-чувствительных-данных" aria-label="Permalink to &quot;Шаг 3: Проверка результата удаления чувствительных данных&quot;">​</a></h3><p>Мы можем проверить, действительно ли только что введенный пароль не был сохранен, с помощью поиска.</p><p><strong>Действие</strong>: Пусть Agent ищет только что сохраненную память:</p><blockquote><p>Поиск пароля базы данных производственной среды.</p></blockquote><p><strong>Ожидаемый результат</strong>: Содержание, которое Agent извлекает из Supermemory, должно быть: <code>IP базы данных в производственной среде - 192.168.1.10, но пароль root - [REDACTED]...</code></p><p>Если Agent говорит вам &quot;пароль - [REDACTED]&quot;, это означает, что механизм удаления чувствительных данных работает нормально.</p><h2 id="распространенные-заблуждения" tabindex="-1">Распространенные заблуждения <a class="header-anchor" href="#распространенные-заблуждения" aria-label="Permalink to &quot;Распространенные заблуждения&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Заблуждение 1: весь код будет загружен</p><p><strong>Факт</strong>: Плагин <strong>не</strong> автоматически загружает всю вашу кодовую базу. Он загружает только конкретные фрагменты при выполнении инициализации сканирования <code>/supermemory-init</code> или когда Agent явно решает &quot;запомнить&quot; логику кода.</p></div><div class="warning custom-block"><p class="custom-block-title">Заблуждение 2: файл .env будет загружен автоматически</p><p><strong>Факт</strong>: Плагин читает <code>SUPERMEMORY_API_KEY</code> из среды процесса. Если вы поместите файл <code>.env</code> в корень проекта, плагин <strong>не</strong> автоматически прочитает его, если только ваша используемая терминал или основная программа OpenCode не загрузила его.</p></div><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы просмотреть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Логика удаления чувствительных данных</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>Загрузка API Key</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>Удаление чувствительных данных при вызове плагина</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>Ключевые функции</strong>:</p><ul><li><code>stripPrivateContent(content)</code>: Выполняет замену регулярными выражениями, превращая содержимое <code>&lt;private&gt;</code> в <code>[REDACTED]</code>.</li><li><code>loadConfig()</code>: Загружает файл локальной конфигурации, приоритет выше переменных среды.</li></ul></details><h2 id="предпросмотр-следующего-урока" tabindex="-1">Предпросмотр следующего урока <a class="header-anchor" href="#предпросмотр-следующего-урока" aria-label="Permalink to &quot;Предпросмотр следующего урока&quot;">​</a></h2><blockquote><p>Поздравляем с завершением основных уроков opencode-supermemory!</p><p>Далее вы можете:</p><ul><li>Вернуться к <a href="/docs/opencodedocs/ru/supermemoryai/opencode-supermemory/advanced/configuration/">Расширенной настройке</a> для получения дополнительных пользовательских опций.</li></ul></blockquote>',35)])])}const g=o(s,[["render",i]]);export{m as __pageData,g as default};
